@app.route("/login")
def login():
    if not _is_configured():
        abort(500, "OIDC client not configured. Set OIDC_CLIENT_ID, OIDC_REDIRECT_URI, and OIDC_AUTHORIZATION_ENDPOINT or OIDC_ISSUER.")

    state = secrets.token_urlsafe(24)
    session["oidc_state"] = state

    params = {
        "client_id": OIDC_CLIENT_ID,
        "redirect_uri": OIDC_REDIRECT_URI,
        "scope": OIDC_SCOPE,
        "response_type": "id_token",
        "response_mode": "form_post",
        "state": state,
    }

    url = OIDC_AUTHORIZATION_ENDPOINT + ("&" if "?" in OIDC_AUTHORIZATION_ENDPOINT else "?") + urlencode(params)
    return redirect(url, code=302)


@app.route("/oidc/callback", methods=["GET", "POST"])
def oidc_callback():
    data = request.form if request.method == "POST" else request.args
    if "error" in data:
        return f"OIDC error: {data.get('error')}\n{data.get('error_description', '')}\n", 400

    state = data.get("state")
    expected_state = session.get("oidc_state")
    if not expected_state or not state or state != expected_state:
        return "Invalid state\n", 400

    id_token = data.get("id_token")
